mapper.sql:
WHERE 1 = 1




      AND L.SBK_NO LIKE CONCAT('%', #{item.searchWord}, '%')

      AND L.USER_ID = #{item.searchWord}

      AND DATE_FORMAT(L.CREAT_DT, '%Y%m%d') BETWEEN DATE_FORMAT(#{item.startDate}, '%Y%m%d') AND DATE_FORMAT(#{item.endDate}, '%Y%m%d')

      AND (
        L.FILE_NAME LIKE CONCAT('%', #{item.searchWord}, '%')
        OR L.DAV_PATH LIKE CONCAT('%', #{item.searchWord}, '%')
      )

      AND L.OP_TYPE = #{item.searchWord}

      AND L.IS_FOLDER = 'Y'
      AND L.IS_FOLDER = 'N'

      AND L.UPLOAD_SRC = #{item.searchWord}

      AND L.RESULT_CD = #{item.searchWord}

      AND L.DEPT LIKE CONCAT('%', #{item.searchWord}, '%')
